#include <stdio.h>
#include <stdlib.h>

int maxQuality(int **dishes, int *sizes, int n) {
    int maxQuality = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < sizes[i]; j++) {
            int quality = 0;
            int last = dishes[i][j];
            for (int k = i + 1; k < n; k++) {
                int maxDiff = 0;
                for (int l = 0; l < sizes[k]; l++) {
                    int diff = abs(last - dishes[k][l]);
                    if (diff > maxDiff) {
                        maxDiff = diff;
                    }
                }
                quality += maxDiff * (k + 1);
                last = dishes[k][sizes[k] - 1];
            }
            if (quality > maxQuality) {
                maxQuality = quality;
            }
        }
    }
    return maxQuality;
}

int main() {
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        int n;
        scanf("%d", &n);
        int **dishes = (int **)malloc(n * sizeof(int *));
        int *sizes = (int *)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            scanf("%d", &sizes[j]);
            dishes[j] = (int *)malloc(sizes[j] * sizeof(int));
            for (int k = 0; k < sizes[j]; k++) {
                scanf("%d", &dishes[j][k]);
            }
        }
        printf("%d\n", maxQuality(dishes, sizes, n));
        for (int j = 0; j < n; j++) {
            free(dishes[j]);
        }
        free(dishes);
        free(sizes);
    }
    return 0;
}

