import java.util.Scanner;
public class Main {
    public static int maxQuality(int[][] dishes) {
        int maxQuality = 0;
        for (int i = 0; i < dishes.length; i++) {
            for (int j = 0; j < dishes[i].length; j++) {
                int quality = 0;
                int last = dishes[i][j];
                for (int k = i + 1; k < dishes.length; k++) {
                    int maxDiff = 0;
                    for (int l = 0; l < dishes[k].length; l++) {
                        int diff = Math.abs(last - dishes[k][l]);
                        if (diff > maxDiff) {
                            maxDiff = diff;
                        }
                    }
                    quality += maxDiff * (k + 1);
                    last = dishes[k][dishes[k].length - 1];
                }
                if (quality > maxQuality) {
                    maxQuality = quality;
                }
            }
        }
        return maxQuality;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        for (int i = 0; i < t; i++) {
            int n = scanner.nextInt();
            int[][] dishes = new int[n][];
            for (int j = 0; j < n; j++) {
                int m = scanner.nextInt();
                dishes[j] = new int[m];
                for (int k = 0; k < m; k++) {
                    dishes[j][k] = scanner.nextInt();
                }
            }
            System.out.println(maxQuality(dishes));
        }
    }
}

